        g_CollisionAABBs.push_back({ glm::vec3(xz_min - wall_t, y_max,           xz_min - wall_t), glm::vec3(xz_max + wall_t, y_max + wall_t, xz_max + wall_t) });
        // Paredes em x = xz_min e x = xz_max
        g_CollisionAABBs.push_back({ glm::vec3(xz_min - wall_t, y_min, xz_min - wall_t), glm::vec3(xz_min,           y_max, xz_max + wall_t) });
        g_CollisionAABBs.push_back({ glm::vec3(xz_max,          y_min, xz_min - wall_t), glm::vec3(xz_max + wall_t, y_max, xz_max + wall_t) });
        // Paredes em z = xz_min e z = xz_max
        g_CollisionAABBs.push_back({ glm::vec3(xz_min - wall_t, y_min, xz_min - wall_t), glm::vec3(xz_max + wall_t, y_max, xz_min) });
        g_CollisionAABBs.push_back({ glm::vec3(xz_min - wall_t, y_min, xz_max),          glm::vec3(xz_max + wall_t, y_max, xz_max + wall_t) });
    };

    add_room_aabbs(sala1_min, sala1_max); // Sala 1: x,z em [-4,+4]
    add_room_aabbs(sala2_min, sala2_max); // Sala 2: x,z em [+4.2,+12]
    // Nota: a parede x=+4 da Sala 1 contém a porta. Por enquanto ela é tratada
    // como sólida (porta sempre fechada para fins de colisão); revisar quando
    // a mecânica de portais/abertura de porta for implementada.

    // Cubo: mesma matriz "model" usada para desenhá-lo (Matrix_Translate(+11,-0.75,5) * Matrix_Scale(1/8,1/8,1/8))
    glm::mat4 model_cube = Matrix_Translate(+11.0f, -0.75f, 5.0f) * Matrix_Scale(1.0f/8.0f, 1.0f/8.0f, 1.0f/8.0f);
    g_CollisionAABBs.push_back(ComputeWorldAABB(g_VirtualScene["Cube"].bbox_min, g_VirtualScene["Cube"].bbox_max, model_cube));

    // Botão: mesma matriz "model" usada para desenhá-lo (Matrix_Translate(9,-1,-1) * Matrix_Scale(1.65,1.65,1.65))
    glm::mat4 model_button = Matrix_Translate(9.0f, -1.0f, -1.0f) * Matrix_Scale(1.65f, 1.65f, 1.65f);
    g_CollisionAABBs.push_back(ComputeWorldAABB(g_VirtualScene["portal_button_reduced_2"].bbox_min, g_VirtualScene["portal_button_reduced_2"].bbox_max, model_button));
}

